import{_ as t,c as a,o,ax as l}from"./chunks/framework.DHqKNX4U.js";const p=JSON.parse('{"title":"Legal Holds: User Interface Guide","description":"","frontmatter":{},"headers":[],"relativePath":"enterprise/legal-holds/guide.md","filePath":"enterprise/legal-holds/guide.md"}'),i={name:"enterprise/legal-holds/guide.md"};function n(r,e,s,d,h,c){return o(),a("div",null,e[0]||(e[0]=[l('<h1 id="legal-holds-user-interface-guide" tabindex="-1">Legal Holds: User Interface Guide <a class="header-anchor" href="#legal-holds-user-interface-guide" aria-label="Permalink to &quot;Legal Holds: User Interface Guide&quot;">​</a></h1><p>The legal holds management interface is located at <strong>Dashboard → Compliance → Legal Holds</strong>. It provides a complete view of all configured holds and tools for creating, applying, releasing, and deactivating them. Per-email hold controls are also available on each archived email&#39;s detail page.</p><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>Legal holds suspend all automated and manual deletion for specific emails, regardless of any retention labels or policies that might otherwise govern them. They are the highest-priority mechanism in the data lifecycle and are intended for use by compliance officers and legal counsel responding to litigation, investigations, or audit requests.</p><h2 id="holds-table" tabindex="-1">Holds Table <a class="header-anchor" href="#holds-table" aria-label="Permalink to &quot;Holds Table&quot;">​</a></h2><p>The main page displays a table of all legal holds with the following columns:</p><ul><li><strong>Name:</strong> The hold name and its UUID displayed underneath for reference.</li><li><strong>Reason:</strong> A short excerpt of the hold&#39;s reason/description. Shows <em>&quot;No reason provided&quot;</em> if omitted.</li><li><strong>Emails:</strong> A badge showing how many archived emails are currently linked to this hold.</li><li><strong>Status:</strong> A badge indicating whether the hold is: <ul><li><strong>Active</strong> (red badge): The hold is currently granting deletion immunity to linked emails.</li><li><strong>Inactive</strong> (gray badge): The hold is deactivated; linked emails are no longer immune.</li></ul></li><li><strong>Created At:</strong> The date the hold was created, in local date format.</li><li><strong>Actions:</strong> Dropdown menu with options depending on the hold&#39;s state (see below).</li></ul><p>The table is sorted by creation date in ascending order.</p><h2 id="creating-a-hold" tabindex="-1">Creating a Hold <a class="header-anchor" href="#creating-a-hold" aria-label="Permalink to &quot;Creating a Hold&quot;">​</a></h2><p>Click the <strong>&quot;Create New&quot;</strong> button above the table to open the creation dialog. New holds are always created in the <strong>Active</strong> state.</p><h3 id="form-fields" tabindex="-1">Form Fields <a class="header-anchor" href="#form-fields" aria-label="Permalink to &quot;Form Fields&quot;">​</a></h3><ul><li><strong>Name</strong> (Required): A unique, descriptive name. Maximum 255 characters.<br> Examples: <code>&quot;Project Titan Litigation — 2026&quot;</code>, <code>&quot;SEC Investigation Q3 2025&quot;</code></li><li><strong>Reason</strong> (Optional): A free-text description of the legal basis for the hold. Maximum 2 000 characters. This appears in the audit log and is visible to other compliance officers.</li></ul><h3 id="after-creation" tabindex="-1">After Creation <a class="header-anchor" href="#after-creation" aria-label="Permalink to &quot;After Creation&quot;">​</a></h3><p>The hold immediately becomes active. No emails are linked to it yet — use Bulk Apply or the individual email detail page to add emails.</p><h2 id="editing-a-hold" tabindex="-1">Editing a Hold <a class="header-anchor" href="#editing-a-hold" aria-label="Permalink to &quot;Editing a Hold&quot;">​</a></h2><p>Click <strong>Edit</strong> from the actions dropdown to modify the hold&#39;s name or reason. The <code>isActive</code> state is changed separately via the <strong>Activate / Deactivate</strong> action.</p><h2 id="activating-and-deactivating-a-hold" tabindex="-1">Activating and Deactivating a Hold <a class="header-anchor" href="#activating-and-deactivating-a-hold" aria-label="Permalink to &quot;Activating and Deactivating a Hold&quot;">​</a></h2><p>The <strong>Deactivate</strong> / <strong>Activate</strong> option appears inline in the actions dropdown. Changing the active state does not remove any email links — it only determines whether those links grant deletion immunity.</p><blockquote><p><strong>Important:</strong> Deactivating a hold means that all emails linked <em>solely</em> to this hold lose their deletion immunity immediately. If any such emails have an expired retention period, they will be permanently deleted on the very next lifecycle worker cycle.</p></blockquote><h2 id="deleting-a-hold" tabindex="-1">Deleting a Hold <a class="header-anchor" href="#deleting-a-hold" aria-label="Permalink to &quot;Deleting a Hold&quot;">​</a></h2><p>A hold <strong>cannot be deleted while it is active</strong>. Attempting to delete an active hold returns a <code>409 Conflict</code> error with the message: <em>&quot;Cannot delete an active legal hold. Deactivate it first...&quot;</em></p><p>To delete a hold:</p><ol><li><strong>Deactivate</strong> it first using the Activate/Deactivate action.</li><li>Click <strong>Delete</strong> from the actions dropdown.</li><li>Confirm in the dialog.</li></ol><p>Deletion permanently removes the hold record and, via database CASCADE, all <code>email_legal_holds</code> link rows. The emails themselves are not deleted — they simply lose the protection that this hold was providing. Any other active holds on those emails continue to protect them.</p><h2 id="bulk-apply" tabindex="-1">Bulk Apply <a class="header-anchor" href="#bulk-apply" aria-label="Permalink to &quot;Bulk Apply&quot;">​</a></h2><p>The <strong>Bulk Apply</strong> option (available only on active holds) opens a search dialog that lets you cast a preservation net across potentially thousands of emails in a single operation.</p><h3 id="search-fields" tabindex="-1">Search Fields <a class="header-anchor" href="#search-fields" aria-label="Permalink to &quot;Search Fields&quot;">​</a></h3><ul><li><strong>Full-text query:</strong> Keywords to match against email subject, body, and attachment content. This uses Meilisearch&#39;s full-text engine with typo tolerance.</li><li><strong>From (sender):</strong> Filter by sender email address.</li><li><strong>Start date / End date:</strong> Filter by the date range of the email&#39;s <code>sentAt</code> field.</li></ul><p>At least one of these fields must be filled before the <strong>Apply Hold</strong> button becomes enabled.</p><h3 id="what-happens-during-bulk-apply" tabindex="-1">What Happens During Bulk Apply <a class="header-anchor" href="#what-happens-during-bulk-apply" aria-label="Permalink to &quot;What Happens During Bulk Apply&quot;">​</a></h3><ol><li>The system pages through all Meilisearch results matching the query (1 000 hits per page).</li><li>Each hit&#39;s email ID is validated against the database to discard any stale index entries.</li><li>New hold links are inserted in batches of 500. Emails already linked to this hold are skipped (idempotent).</li><li>A success notification shows <strong>how many emails were newly placed under the hold</strong> (already-protected emails are not counted again).</li><li>The exact search query JSON is written to the audit log as GoBD proof of the scope of protection.</li></ol><blockquote><p><strong>Warning:</strong> Bulk Apply is a wide-net operation. Review your query carefully — there is no per-email confirmation step. Use the search page first to preview results before applying.</p></blockquote><h3 id="bulk-apply-and-the-audit-log" tabindex="-1">Bulk Apply and the Audit Log <a class="header-anchor" href="#bulk-apply-and-the-audit-log" aria-label="Permalink to &quot;Bulk Apply and the Audit Log&quot;">​</a></h3><p>The audit log entry for a bulk apply contains:</p><ul><li><code>action: &quot;BulkApplyHold&quot;</code></li><li><code>searchQuery</code>: the exact JSON query used</li><li><code>emailsLinked</code>: number of emails newly linked</li><li><code>emailsAlreadyProtected</code>: number of emails that were already under this hold</li></ul><h2 id="release-all-emails" tabindex="-1">Release All Emails <a class="header-anchor" href="#release-all-emails" aria-label="Permalink to &quot;Release All Emails&quot;">​</a></h2><p>The <strong>Release All</strong> option (available when the hold has at least one linked email) removes every <code>email_legal_holds</code> link for this hold in a single operation.</p><blockquote><p><strong>Warning:</strong> This immediately lifts deletion immunity for all emails that were solely protected by this hold. Emails with expired retention periods will be deleted on the next lifecycle worker cycle.</p></blockquote><p>A confirmation dialog is shown before the operation proceeds. On success, a notification reports how many email links were removed.</p><h2 id="per-email-hold-controls" tabindex="-1">Per-Email Hold Controls <a class="header-anchor" href="#per-email-hold-controls" aria-label="Permalink to &quot;Per-Email Hold Controls&quot;">​</a></h2><h3 id="viewing-holds-on-a-specific-email" tabindex="-1">Viewing Holds on a Specific Email <a class="header-anchor" href="#viewing-holds-on-a-specific-email" aria-label="Permalink to &quot;Viewing Holds on a Specific Email&quot;">​</a></h3><p>On any archived email&#39;s detail page, the <strong>Legal Holds</strong> card lists all holds currently applied to that email, showing:</p><ul><li>Hold name and active/inactive badge</li><li>Date the hold was applied</li></ul><h3 id="applying-a-hold-to-a-specific-email" tabindex="-1">Applying a Hold to a Specific Email <a class="header-anchor" href="#applying-a-hold-to-a-specific-email" aria-label="Permalink to &quot;Applying a Hold to a Specific Email&quot;">​</a></h3><p>In the Legal Holds card, a dropdown lists all currently <strong>active</strong> holds. Select a hold and click <strong>Apply</strong>. The operation is idempotent — applying the same hold twice has no effect.</p><h3 id="removing-a-hold-from-a-specific-email" tabindex="-1">Removing a Hold from a Specific Email <a class="header-anchor" href="#removing-a-hold-from-a-specific-email" aria-label="Permalink to &quot;Removing a Hold from a Specific Email&quot;">​</a></h3><p>Each linked hold in the card has a <strong>Remove</strong> button. Clicking it removes only the link between this email and that specific hold. The hold itself remains and continues to protect other emails.</p><blockquote><p><strong>Note:</strong> Removing the last active hold from an email means the email is no longer immune. If its retention period has expired, it will be deleted on the next lifecycle worker cycle.</p></blockquote><h3 id="delete-button-behaviour-under-a-hold" tabindex="-1">Delete Button Behaviour Under a Hold <a class="header-anchor" href="#delete-button-behaviour-under-a-hold" aria-label="Permalink to &quot;Delete Button Behaviour Under a Hold&quot;">​</a></h3><p>The <strong>Delete Email</strong> button on the email detail page is not disabled in the UI, but the backend will reject the request if the email is under an active hold. An error toast is displayed: <em>&quot;Deletion blocked by retention policy (Legal Hold or similar).&quot;</em></p><h2 id="permissions-reference" tabindex="-1">Permissions Reference <a class="header-anchor" href="#permissions-reference" aria-label="Permalink to &quot;Permissions Reference&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Operation</th><th>Required Permission</th></tr></thead><tbody><tr><td>View holds table</td><td><code>manage:all</code></td></tr><tr><td>Create / edit / delete a hold</td><td><code>manage:all</code></td></tr><tr><td>Activate / deactivate a hold</td><td><code>manage:all</code></td></tr><tr><td>Bulk apply</td><td><code>manage:all</code></td></tr><tr><td>Release all emails from a hold</td><td><code>manage:all</code></td></tr><tr><td>View holds on a specific email</td><td><code>read:archive</code></td></tr><tr><td>Apply / remove a hold from email</td><td><code>manage:all</code></td></tr></tbody></table><h2 id="workflow-responding-to-a-litigation-notice" tabindex="-1">Workflow: Responding to a Litigation Notice <a class="header-anchor" href="#workflow-responding-to-a-litigation-notice" aria-label="Permalink to &quot;Workflow: Responding to a Litigation Notice&quot;">​</a></h2><ol><li><strong>Receive the litigation notice.</strong> Identify the relevant custodians, date range, and keywords.</li><li><strong>Create a hold</strong>: Navigate to Dashboard → Compliance → Legal Holds and click <strong>Create New</strong>. Name it descriptively (e.g., <code>&quot;Doe v. Acme Corp — 2026&quot;</code>). Add the legal matter reference as the reason.</li><li><strong>Bulk apply</strong>: Click <strong>Bulk Apply</strong> on the new hold. Enter keywords, the custodian&#39;s email address in the <strong>From</strong> field, and the relevant date range. Submit.</li><li><strong>Verify</strong>: Check the email count badge on the hold row. Review the audit log to confirm the search query was recorded.</li><li><strong>Individual additions</strong>: If specific emails not captured by the bulk query need to be preserved, open each email&#39;s detail page and apply the hold manually.</li><li><strong>When the matter concludes</strong>: Click <strong>Deactivate</strong> on the hold, then <strong>Release All</strong> to remove all email links, and finally <strong>Delete</strong> the hold record if desired.</li></ol><h2 id="troubleshooting" tabindex="-1">Troubleshooting <a class="header-anchor" href="#troubleshooting" aria-label="Permalink to &quot;Troubleshooting&quot;">​</a></h2><h3 id="cannot-delete-hold-—-cannot-delete-an-active-legal-hold" tabindex="-1">Cannot Delete Hold — &quot;Cannot delete an active legal hold&quot; <a class="header-anchor" href="#cannot-delete-hold-—-cannot-delete-an-active-legal-hold" aria-label="Permalink to &quot;Cannot Delete Hold — &quot;Cannot delete an active legal hold&quot;&quot;">​</a></h3><p><strong>Cause:</strong> The hold is still active.<br><strong>Solution:</strong> Use the <strong>Deactivate</strong> option from the actions dropdown first.</p><h3 id="bulk-apply-returns-0-emails" tabindex="-1">Bulk Apply Returns 0 Emails <a class="header-anchor" href="#bulk-apply-returns-0-emails" aria-label="Permalink to &quot;Bulk Apply Returns 0 Emails&quot;">​</a></h3><p><strong>Cause 1:</strong> The search query matched no documents in the Meilisearch index.<br><strong>Solution:</strong> Verify the query in the main Search page to preview results before applying.<br><strong>Cause 2:</strong> All Meilisearch results were stale (emails deleted from the archive before this operation).<br><strong>Solution:</strong> This is a data state issue; the stale index entries will be cleaned up on the next index rebuild.</p><h3 id="delete-email-returns-an-error-instead-of-deleting" tabindex="-1">Delete Email Returns an Error Instead of Deleting <a class="header-anchor" href="#delete-email-returns-an-error-instead-of-deleting" aria-label="Permalink to &quot;Delete Email Returns an Error Instead of Deleting&quot;">​</a></h3><p><strong>Cause:</strong> The email is under one or more active legal holds.<br><strong>Solution:</strong> This is expected behavior. Deactivate or remove the hold(s) from this email before deleting.</p><h3 id="hold-emails-count-shows-0-after-bulk-apply" tabindex="-1">Hold Emails Count Shows 0 After Bulk Apply <a class="header-anchor" href="#hold-emails-count-shows-0-after-bulk-apply" aria-label="Permalink to &quot;Hold Emails Count Shows 0 After Bulk Apply&quot;">​</a></h3><p><strong>Cause:</strong> The <code>emailCount</code> field is fetched when the page loads. If the bulk operation was just completed, refresh the page to see the updated count.</p>',63)]))}const u=t(i,[["render",n]]);export{p as __pageData,u as default};
